import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const ALLOWED_ORIGINS = [
  "https://crevia.app",
  "https://www.crevia.app",
  "http://localhost:8080",
  "http://localhost:5173",
  "https://creviamvp.vercel.app",
];

function getCorsHeaders(req: Request) {
  const origin = req.headers.get("Origin") ?? "";
  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  return {
    "Access-Control-Allow-Origin": allowed,
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
    "Vary": "Origin",
  };
}

function formatDateTime(date: Date): string {
  return date.toLocaleString("en-US", {
    weekday: "long",
    year: "numeric",
    month: "long",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    timeZone: "UTC",
    timeZoneName: "short",
  });
}

serve(async (req) => {
  const cors = getCorsHeaders(req);

  if (req.method === "OPTIONS") {
    return new Response(null, { headers: cors });
  }

  if (req.method !== "POST") {
    return new Response(JSON.stringify({ error: "Method not allowed" }), {
      status: 405,
      headers: { ...cors, "Content-Type": "application/json" },
    });
  }

  try {
    const authHeader = req.headers.get("Authorization");
    if (!authHeader?.startsWith("Bearer ")) {
      return new Response(JSON.stringify({ error: "Unauthorized" }), {
        status: 401,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    }

    const token = authHeader.replace("Bearer ", "");
    const supabase = createClient(
      Deno.env.get("SUPABASE_URL")!,
      Deno.env.get("SUPABASE_ANON_KEY")!,
    );

    const { data: { user }, error: userError } = await supabase.auth.getUser(token);
    if (userError || !user?.email) {
      return new Response(JSON.stringify({ error: "Invalid token" }), {
        status: 401,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    }

    // Respect the user's preference — default true for new users
    const alertsEnabled = user.user_metadata?.login_alerts_enabled !== false;
    if (!alertsEnabled) {
      return new Response(JSON.stringify({ skipped: true }), {
        status: 200,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    }

    const resendKey = Deno.env.get("RESEND_API_KEY");
    if (!resendKey) {
      return new Response(JSON.stringify({ error: "Email service not configured" }), {
        status: 500,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    }

    const signInTime = formatDateTime(new Date());
    const settingsUrl = "https://creviamvp.vercel.app/settings?tab=security";
    const displayName = user.user_metadata?.full_name || user.email;

    const html = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>New sign-in to your Crevia account</title>
</head>
<body style="margin:0;padding:0;background:#f9f9f7;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f9f9f7;padding:40px 16px;">
    <tr>
      <td align="center">
        <table width="100%" cellpadding="0" cellspacing="0" style="max-width:520px;background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,0.08);">
          <!-- Header -->
          <tr>
            <td style="background:#1a1a1a;padding:28px 40px;">
              <img src="https://creviamvp.vercel.app/crevia-logo.png" alt="Crevia" height="36" style="display:block;" />
            </td>
          </tr>
          <!-- Body -->
          <tr>
            <td style="padding:36px 40px 28px;">
              <p style="margin:0 0 8px;font-size:20px;font-weight:700;color:#111;">New sign-in detected</p>
              <p style="margin:0 0 24px;font-size:14px;color:#555;line-height:1.6;">
                Hi ${displayName},<br/>
                We detected a new sign-in to your Crevia account.
              </p>

              <table width="100%" cellpadding="0" cellspacing="0" style="background:#f5f4f0;border-radius:8px;padding:20px;margin-bottom:24px;">
                <tr>
                  <td>
                    <p style="margin:0 0 6px;font-size:11px;font-weight:600;color:#888;text-transform:uppercase;letter-spacing:0.8px;">Time</p>
                    <p style="margin:0;font-size:14px;color:#222;font-weight:500;">${signInTime}</p>
                  </td>
                </tr>
              </table>

              <p style="margin:0 0 20px;font-size:14px;color:#555;line-height:1.6;">
                If this was you, no action is needed.<br/>
                If this <strong>wasn't you</strong>, secure your account immediately.
              </p>

              <a href="${settingsUrl}" style="display:inline-block;background:#c9a96e;color:#ffffff;text-decoration:none;font-size:14px;font-weight:600;padding:12px 24px;border-radius:8px;">
                Secure My Account
              </a>
            </td>
          </tr>
          <!-- Footer -->
          <tr>
            <td style="padding:20px 40px 28px;border-top:1px solid #f0ede8;">
              <p style="margin:0;font-size:12px;color:#aaa;line-height:1.6;">
                You received this because login alerts are enabled for your account.<br/>
                To turn them off, visit <a href="${settingsUrl}" style="color:#c9a96e;text-decoration:none;">Settings → Security</a>.
              </p>
            </td>
          </tr>
        </table>
      </td>
    </tr>
  </table>
</body>
</html>`;

    const emailRes = await fetch("https://api.resend.com/emails", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${resendKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        from: "Crevia Security <security@crevia.app>",
        to: user.email,
        subject: "New sign-in to your Crevia account",
        html,
      }),
    });

    if (!emailRes.ok) {
      const err = await emailRes.text();
      console.error("Resend error:", err);
      return new Response(JSON.stringify({ error: "Failed to send email" }), {
        status: 500,
        headers: { ...cors, "Content-Type": "application/json" },
      });
    }

    return new Response(JSON.stringify({ sent: true }), {
      status: 200,
      headers: { ...cors, "Content-Type": "application/json" },
    });
  } catch (err) {
    console.error("login-alert error:", err);
    return new Response(JSON.stringify({ error: "Internal server error" }), {
      status: 500,
      headers: { ...cors, "Content-Type": "application/json" },
    });
  }
});

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const ADMIN_EMAIL = "anthony.onyango@student.moringaschool.com";
const FROM_EMAIL = "noreply@crevia.app";
const RESEND_URL = "https://api.resend.com/emails";

const ALLOWED_ORIGINS = [
  "https://crevia.app",
  "https://www.crevia.app",
  "http://localhost:8080",
  "http://localhost:5173",
  "https://creviamvp.vercel.app",
];

function getCorsHeaders(req: Request) {
  const origin = req.headers.get("Origin") ?? "";
  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  return {
    "Access-Control-Allow-Origin": allowed,
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
    "Vary": "Origin",
  };
}

serve(async (req: Request) => {
  const cors = getCorsHeaders(req);
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: cors });
  }

  try {
    const resendKey = Deno.env.get("RESEND_API_KEY");
    if (!resendKey) throw new Error("RESEND_API_KEY not configured");

    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const serviceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
    const supabase = createClient(supabaseUrl, serviceKey);

    // Verify caller is authenticated (can be called by webhook or authenticated user)
    const authHeader = req.headers.get("Authorization");
    let callerUserId: string | null = null;
    if (authHeader) {
      const anonKey = Deno.env.get("SUPABASE_ANON_KEY")!;
      const userClient = createClient(supabaseUrl, anonKey, {
        global: { headers: { Authorization: authHeader } },
      });
      const { data: { user } } = await userClient.auth.getUser();
      callerUserId = user?.id ?? null;
    }

    const body = await req.json();
    const { feedback_id, message, type, user_email, user_name } = body;

    // If feedback_id provided, fetch from DB; otherwise use body fields directly (webhook path)
    let feedbackMessage = message;
    let feedbackType = type ?? "thought";
    let submitterEmail = user_email ?? "Anonymous";
    let submitterName = user_name ?? "Anonymous";
    let submittedAt = new Date().toISOString();

    if (feedback_id) {
      const { data: fb, error: fbErr } = await supabase
        .from("feedback")
        .select("id, type, title, message, created_at, user_id")
        .eq("id", feedback_id)
        .single();

      if (fbErr || !fb) throw new Error("Feedback record not found");

      feedbackMessage = fb.message;
      feedbackType = fb.type;
      submittedAt = fb.created_at;

      if (fb.user_id) {
        const { data: profile } = await supabase
          .from("profiles")
          .select("full_name, email")
          .eq("id", fb.user_id)
          .single();
        if (profile) {
          submitterName = (profile as any).display_name ?? (profile as any).full_name ?? "Unknown";
          submitterEmail = profile.email ?? "Unknown";
        }
      }
    }

    const typeLabel = feedbackType === "feature" ? "Feature Request" : "Thought / Feedback";
    const formattedDate = new Date(submittedAt).toLocaleString("en-GB", {
      day: "2-digit", month: "short", year: "numeric",
      hour: "2-digit", minute: "2-digit",
    });

    const html = `
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0" />
<title>New Feedback — Crevia</title>
<style>
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f5f4f0; margin: 0; padding: 32px 16px; color: #1a1a1a; }
  .card { background: #fff; max-width: 560px; margin: 0 auto; border-radius: 16px; overflow: hidden; box-shadow: 0 2px 16px rgba(0,0,0,0.08); }
  .header { background: #1a1a1a; padding: 28px 32px; }
  .header h1 { color: #fff; font-size: 20px; margin: 0 0 4px; font-weight: 600; }
  .header p { color: #999; font-size: 13px; margin: 0; }
  .badge { display: inline-block; background: #c8a876; color: #fff; font-size: 11px; font-weight: 600; padding: 3px 10px; border-radius: 20px; letter-spacing: 0.5px; text-transform: uppercase; margin-bottom: 16px; }
  .body { padding: 28px 32px; }
  .label { font-size: 11px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.8px; color: #999; margin-bottom: 4px; }
  .value { font-size: 14px; color: #1a1a1a; margin-bottom: 20px; }
  .message-box { background: #f9f8f5; border-left: 3px solid #c8a876; padding: 16px 20px; border-radius: 0 8px 8px 0; font-size: 14px; line-height: 1.7; color: #333; white-space: pre-wrap; word-break: break-word; }
  .footer { padding: 16px 32px; background: #f9f8f5; border-top: 1px solid #eee; font-size: 12px; color: #999; }
</style>
</head>
<body>
<div class="card">
  <div class="header">
    <img src="https://creviamvp.vercel.app/crevia-logo.png" alt="Crevia" height="32" style="display:block;margin-bottom:12px;" />
    <h1>New Feedback Received</h1>
    <p>Submitted via Crevia · ${formattedDate}</p>
  </div>
  <div class="body">
    <div class="badge">${typeLabel}</div>

    <div class="label">From</div>
    <div class="value">${submitterName} &lt;${submitterEmail}&gt;</div>

    <div class="label">Message</div>
    <div class="message-box">${feedbackMessage.replace(/</g, "&lt;").replace(/>/g, "&gt;")}</div>
  </div>
  <div class="footer">Crevia Admin · Do not reply to this email</div>
</div>
</body>
</html>`;

    const res = await fetch(RESEND_URL, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${resendKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        from: `Crevia Feedback <${FROM_EMAIL}>`,
        to: [ADMIN_EMAIL],
        subject: `[Crevia Feedback] ${typeLabel} from ${submitterName}`,
        html,
      }),
    });

    if (!res.ok) {
      const errText = await res.text();
      throw new Error(`Resend error ${res.status}: ${errText}`);
    }

    const resData = await res.json();

    return new Response(
      JSON.stringify({ success: true, email_id: resData.id }),
      { headers: { ...cors, "Content-Type": "application/json" } }
    );
  } catch (err: any) {
    console.error("[feedback-notify]", err.message);
    return new Response(
      JSON.stringify({ error: err.message }),
      { status: 500, headers: { ...cors, "Content-Type": "application/json" } }
    );
  }
});

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const ADMIN_EMAIL = "anthony.onyango@student.moringaschool.com";
const FROM_EMAIL  = "noreply@crevia.app";
const RESEND_URL  = "https://api.resend.com/emails";

const ALLOWED_ORIGINS = [
  "https://crevia.app",
  "https://www.crevia.app",
  "http://localhost:8080",
  "http://localhost:5173",
  "https://creviamvp.vercel.app",
];

function getCorsHeaders(req: Request) {
  const origin  = req.headers.get("Origin") ?? "";
  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  return {
    "Access-Control-Allow-Origin": allowed,
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
    "Vary": "Origin",
  };
}

serve(async (req: Request) => {
  const cors = getCorsHeaders(req);
  if (req.method === "OPTIONS") return new Response("ok", { headers: cors });

  try {
    const resendKey = Deno.env.get("RESEND_API_KEY");
    if (!resendKey) throw new Error("RESEND_API_KEY not configured");

    const supabase = createClient(
      Deno.env.get("SUPABASE_URL")!,
      Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!,
    );

    const { request_id } = await req.json();
    if (!request_id) throw new Error("request_id is required");

    // Fetch verification request + profile
    const { data: vr, error: vrErr } = await supabase
      .from("verification_requests")
      .select("*, profiles:user_id(display_name, handle, email, avatar_url)")
      .eq("id", request_id)
      .single();

    if (vrErr || !vr) throw new Error("Verification request not found");

    const profile     = (vr as any).profiles ?? {};
    const name        = profile.display_name || profile.handle || "Unknown";
    const email       = profile.email        || "—";
    const handle      = profile.handle       || "—";
    const submittedAt = new Date(vr.created_at).toLocaleString("en-GB", {
      day: "2-digit", month: "short", year: "numeric",
      hour: "2-digit", minute: "2-digit",
    });

    const socialRows = [
      vr.instagram_handle && `<tr><td style="padding:6px 0;color:#888;font-size:13px;width:110px">Instagram</td><td style="padding:6px 0;font-size:13px;font-weight:600;color:#1a1a1a">@${vr.instagram_handle}</td></tr>`,
      vr.tiktok_handle    && `<tr><td style="padding:6px 0;color:#888;font-size:13px">TikTok</td><td style="padding:6px 0;font-size:13px;font-weight:600;color:#1a1a1a">@${vr.tiktok_handle}</td></tr>`,
      vr.youtube_handle   && `<tr><td style="padding:6px 0;color:#888;font-size:13px">YouTube</td><td style="padding:6px 0;font-size:13px;font-weight:600;color:#1a1a1a">${vr.youtube_handle}</td></tr>`,
      vr.twitter_handle   && `<tr><td style="padding:6px 0;color:#888;font-size:13px">X / Twitter</td><td style="padding:6px 0;font-size:13px;font-weight:600;color:#1a1a1a">@${vr.twitter_handle}</td></tr>`,
      vr.follower_count   && `<tr><td style="padding:6px 0;color:#888;font-size:13px">Followers</td><td style="padding:6px 0;font-size:13px;font-weight:600;color:#1a1a1a">${Number(vr.follower_count).toLocaleString()}</td></tr>`,
    ].filter(Boolean).join("");

    const html = `
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0" />
<title>New Verification Request — Crevia</title>
</head>
<body style="margin:0;padding:32px 16px;background:#f5f4f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;color:#1a1a1a;">
<table width="100%" cellpadding="0" cellspacing="0"><tr><td align="center">
<table width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 2px 16px rgba(0,0,0,0.08);">

  <!-- Header -->
  <tr><td style="background:#1a1a1a;padding:28px 32px;">
    <img src="https://creviamvp.vercel.app/crevia-logo.png" alt="Crevia" height="32" style="display:block;margin-bottom:12px;" />
    <p style="margin:0 0 4px;font-size:20px;font-weight:700;color:#fff;">New Verification Request</p>
    <p style="margin:0;font-size:13px;color:#888;">Submitted via Crevia · ${submittedAt}</p>
  </td></tr>

  <!-- Body -->
  <tr><td style="padding:28px 32px;">
    <p style="margin:0 0 6px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.8px;color:#999;">From</p>
    <p style="margin:0 0 24px;font-size:15px;font-weight:600;color:#1a1a1a;">${name} &lt;${email}&gt; · @${handle}</p>

    ${socialRows ? `
    <p style="margin:0 0 8px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.8px;color:#999;">Social Handles</p>
    <table style="background:#f9f8f5;border-radius:8px;padding:12px 16px;margin-bottom:24px;width:100%;border-collapse:collapse;">
      ${socialRows}
    </table>` : ""}

    <p style="margin:0 0 8px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.8px;color:#999;">Reason</p>
    <div style="background:#f9f8f5;border-left:3px solid #c8a876;padding:16px 20px;border-radius:0 8px 8px 0;font-size:14px;line-height:1.7;color:#333;white-space:pre-wrap;word-break:break-word;">${String(vr.reason ?? "").replace(/</g, "&lt;").replace(/>/g, "&gt;")}</div>

    <p style="margin:24px 0 0;font-size:13px;color:#888;">Review this request in your <strong style="color:#1a1a1a;">Crevia Admin → Support</strong> dashboard.</p>
  </td></tr>

  <!-- Footer -->
  <tr><td style="padding:16px 32px;background:#f9f8f5;border-top:1px solid #eee;">
    <p style="margin:0;font-size:12px;color:#aaa;">Crevia Admin · Do not reply to this email</p>
  </td></tr>

</table>
</td></tr></table>
</body>
</html>`;

    const res = await fetch(RESEND_URL, {
      method: "POST",
      headers: { Authorization: `Bearer ${resendKey}`, "Content-Type": "application/json" },
      body: JSON.stringify({
        from: `Crevia Admin <${FROM_EMAIL}>`,
        to:   [ADMIN_EMAIL],
        subject: `[Crevia] Verification request from ${name}`,
        html,
      }),
    });

    if (!res.ok) {
      const errText = await res.text();
      throw new Error(`Resend error ${res.status}: ${errText}`);
    }

    const resData = await res.json();
    return new Response(JSON.stringify({ success: true, email_id: resData.id }), {
      headers: { ...cors, "Content-Type": "application/json" },
    });

  } catch (err: any) {
    console.error("[verification-notify]", err.message);
    return new Response(JSON.stringify({ error: err.message }), {
      status: 500,
      headers: { ...cors, "Content-Type": "application/json" },
    });
  }
});
